/// Generates build.yaml configuration for Morphy entities
///
/// The build.yaml file configures build_runner to generate .g.dart files
/// for Morphy entities located in lib/src/domain/entities/
class BuildYamlGenerator {
  /// Generate build.yaml content for Morphy code generation
  String generateBuildYaml() {
    return '''
# Generated by Zuraffa
# Configuration for build_runner to generate Morphy entities

targets:
  \$default:
    builders:
      # Morphy builder configuration
      morphy_builder:
        enabled: true
        generate_for:
          - lib/src/domain/entities/*.dart
        options:
          # Generate JSON serialization
          generate_json: true

      # Source_gen builder (Morphy uses this internally)
      source_gen|combining_builder:
        enabled: true

# Global options
global_options:
  morphy_builder:
    options:
      # Ensure .g.dart files are generated
      generate_json: true
''';
  }

  /// Check if build.yaml needs to be created or updated
  /// Returns true if build.yaml doesn't exist or needs Morphy config
  bool needsBuildYaml(String? existingContent) {
    if (existingContent == null || existingContent.isEmpty) {
      return true;
    }

    // Check if it already has Morphy configuration
    return !existingContent.contains('morphy_builder') &&
        !existingContent.contains('lib/src/domain/entities');
  }

  /// Merge Morphy configuration into existing build.yaml
  /// If existing build.yaml exists, add Morphy config to it
  String mergeBuildYaml(String existingContent) {
    // If already has morphy_builder, return as-is
    if (existingContent.contains('morphy_builder')) {
      return existingContent;
    }

    // Simple merge: append Morphy config
    return '''
$existingContent

# === Added by Zuraffa ===
targets:
  \$default:
    builders:
      morphy_builder:
        enabled: true
        generate_for:
          - lib/src/domain/entities/*.dart
        options:
          generate_json: true
''';
  }
}
